const fixtures = [
  {
    json: {
      fixtureKey: 'acuse_sisub',
      context: {
        submission_id: 'sample_sub_acuse',
        expected_document_type: 'acuse_sisub',
        upload_context_version: 1,
        metadata_rules_version: 'v1'
      }
    }
  },
  {
    json: {
      fixtureKey: 'contrato_prestacion_servicios',
      context: {
        submission_id: 'sample_sub_contrato',
        expected_document_type: 'contrato_prestacion_servicios',
        upload_context_version: 1,
        metadata_rules_version: 'v1'
      }
    }
  }
];
return fixtures;

const templates = {
  acuse_sisub: {
    documentType: 'acuse_sisub',
    metadataRulesVersion: 'v1',
    requiredFields: [
      'document_name',
      'area_interna',
      'document_category',
      'document_subtype',
      'document_date',
      'participants',
      'tags'
    ]
  },
  contrato_prestacion_servicios: {
    documentType: 'contrato_prestacion_servicios',
    metadataRulesVersion: 'v1',
    requiredFields: [
      'document_name',
      'document_date',
      'start_date',
      'expiration_date',
      'participants',
      'tags'
    ]
  }
};

return $input.all().map((item) => {
  const fk = item.json.fixtureKey;
  const template = templates[fk] || { documentType: fk, metadataRulesVersion: 'v1', requiredFields: [] };

  item.json.template = template;
  item.json.review_items = template.requiredFields.map((k) => ({
    field_key: k,
    value: null,
    status: 'pending'
  }));

  item.json.review_payload = {
    fixture_key: fk,
    context: item.json.context,
    template,
    review_items: item.json.review_items,
    safety: {
      legal_approval_allowed: false,
      ocr_used: false,
      ai_used: false,
      google_sheets_used: false
    }
  };

  return item;
});
